<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Exploration Game</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
            background-color: #f5f5f5;
        }
        #maze-container {
            display: flex;
            flex-direction: column;
            align-items: center;
        }
        #controls {
            margin-bottom: 10px;
            display: flex;
            gap: 20px;
            align-items: center;
        }
        button {
            padding: 8px 16px;
            font-size: 14px;
            cursor: pointer;
            background-color: #4CAF50;
            color: white;
            border: none;
            border-radius: 4px;
        }
        button:hover {
            background-color: #45a049;
        }
        .stat {
            font-size: 16px;
            font-weight: bold;
        }
        canvas {
            border: 2px solid #333;
            box-shadow: 0 4px 8px rgba(0,0,0,0.2);
            background-color: white;
        }
    </style>
</head>
<body>
    <div id="maze-container">
        <h1>Maze Exploration Game</h1>
        <div id="controls">
            <button id="reset">Reset Maze</button>
            <span class="stat" id="completed">Completed: 0/24</span>
            <span class="stat" id="timer">Time: 0 ticks</span>
        </div>
        <canvas id="maze" width="600" height="600"></canvas>
    </div>

    <script>
        // Random number generator with seed
        class SeededRandom {
            constructor(seed) {
                this.seed = seed;
            }

            next() {
                this.seed = (this.seed * 1103515245 + 12345) & 0x7fffffff;
                return this.seed / 0x7fffffff;
            }
        }

        // Maze generation using recursive backtracking
        class Maze {
            constructor(rows, cols, rng) {
                this.rows = rows;
                this.cols = cols;
                this.rng = rng;

                // Initialize grid with all walls present
                this.walls = [];
                for (let r = 0; r < rows; r++) {
                    const row = [];
                    for (let c = 0; c < cols; c++) {
                        row.push({ n: true, e: true, s: true, w: true });
                    }
                    this.walls.push(row);
                }

                // Generate maze using recursive backtracking
                this.generateMaze();
            }

            generateMaze() {
                const stack = [];
                const visited = new Set();

                // Start at top-left corner (0, 0)
                const startR = Math.floor(this.rows / 2); // Center-ish for spawn
                const startC = Math.floor(this.cols / 2);

                this.spawn = { r: startR, c: startC };

                let current = { r: startR, c: startC };
                visited.add(`${current.r},${current.c}`);
                stack.push(current);

                while (stack.length > 0) {
                    current = stack[stack.length - 1];
                    const neighbors = this.getUnvisitedNeighbors(current, visited);

                    if (neighbors.length > 0) {
                        // Choose random neighbor
                        const next = neighbors[Math.floor(this.rng.next() * neighbors.length)];

                        // Remove walls between current and next
                        this.removeWalls(current, next);

                        visited.add(`${next.r},${next.c}`);
                        stack.push(next);
                    } else {
                        stack.pop();
                    }
                }

                // Set exit at opposite corner from spawn
                const exitR = (startR === 0) ? this.rows - 1 : 0;
                const exitC = (startC === 0) ? this.cols - 1 : 0;

                // Find furthest point from spawn as exit for better gameplay
                let maxDist = -1;
                let bestExit = { r: this.rows - 1, c: this.cols - 1 };

                for (let r = 0; r < this.rows; r++) {
                    for (let c = 0; c < this.cols; c++) {
                        const dist = Math.abs(r - startR) + Math.abs(c - startC);
                        if (dist > maxDist) {
                            // Check if it's a valid exit location (edge of maze)
                            if (r === 0 || r === this.rows - 1 || c === 0 || c === this.cols - 1) {
                                maxDist = dist;
                                bestExit = { r, c };
                            }
                        }
                    }
                }

                this.exit = bestExit;
            }

            getUnvisitedNeighbors(cell, visited) {
                const neighbors = [];
                const directions = [
                    { dr: -1, dc: 0, dir: 'n' },
                    { dr: 0, dc: 1, dir: 'e' },
                    { dr: 1, dc: 0, dir: 's' },
                    { dr: 0, dc: -1, dir: 'w' }
                ];

                for (const d of directions) {
                    const nr = cell.r + d.dr;
                    const nc = cell.c + d.dc;

                    if (nr >= 0 && nr < this.rows && nc >= 0 && nc < this.cols &&
                        !visited.has(`${nr},${nc}`)) {
                        neighbors.push({ r: nr, c: nc });
                    }
                }

                return neighbors;
            }

            removeWalls(cell1, cell2) {
                const dr = cell2.r - cell1.r;
                const dc = cell2.c - cell1.c;

                if (dr === -1 && dc === 0) { // cell2 is north of cell1
                    this.walls[cell1.r][cell1.c].n = false;
                    this.walls[cell2.r][cell2.c].s = false;
                } else if (dr === 1 && dc === 0) { // cell2 is south of cell1
                    this.walls[cell1.r][cell1.c].s = false;
                    this.walls[cell2.r][cell2.c].n = false;
                } else if (dr === 0 && dc === -1) { // cell2 is west of cell1
                    this.walls[cell1.r][cell1.c].w = false;
                    this.walls[cell2.r][cell2.c].e = false;
                } else if (dr === 0 && dc === 1) { // cell2 is east of cell1
                    this.walls[cell1.r][cell1.c].e = false;
                    this.walls[cell2.r][cell2.c].w = false;
                }
            }

            getWalls(r, c) {
                if (r >= 0 && r < this.rows && c >= 0 && c < this.cols) {
                    return { ...this.walls[r][c] };
                }
                // Return walls for out-of-bounds cells
                return { n: true, e: true, s: true, w: true };
            }
        }

        // Bot class with DFS/Tremaux exploration
        class Bot {
            constructor(id, maze, rng) {
                this.id = id;
                this.maze = maze;
                this.rng = rng;

                // Start at spawn position
                this.pos = { r: maze.spawn.r, c: maze.spawn.c };
                this.startPos = { ...this.pos };

                // Bot's knowledge of the maze
                this.knowledge = {};
                this.exploredCells = new Set();
                this.deadEnds = [];
                this.path = [{ r: this.pos.r, c: this.pos.c }];

                // DFS state: track visited directions for each cell
                this.cellVisits = {}; // { "r,c": [directions] }

                // Movement interpolation
                this.interpolationProgress = 0;
                this.fromPos = { ...this.pos };
                this.toPos = null;

                // Finish state
                this.finishTick = null;
                this.isFinished = false;

                // Direction preference order (different for each bot)
                const baseDirs = [
                    [{ dr: -1, dc: 0, dir: 'n' }, { dr: 0, dc: 1, dir: 'e' }, 
                     { dr: 1, dc: 0, dir: 's' }, { dr: 0, dc: -1, dir: 'w' }],
                    [{ dr: 0, dc: 1, dir: 'e' }, { dr: -1, dc: 0, dir: 'n' }, 
                     { dr: 0, dc: -1, dir: 'w' }, { dr: 1, dc: 0, dir: 's' }],
                    [{ dr: 1, dc: 0, dir: 's' }, { dr: 0, dc: -1, dir: 'w' }, 
                     { dr: -1, dc: 0, dir: 'n' }, { dr: 0, dc: 1, dir: 'e' }],
                    [{ dr: 0, dc: -1, dir: 'w' }, { dr: 1, dc: 0, dir: 's' }, 
                     { dr: 0, dc: 1, dir: 'e' }, { dr: -1, dc: 0, dir: 'n' }]
                ];

                // Use seeded random to shuffle directions for variety
                this.directionOrder = baseDirs[id % baseDirs.length].map((d, i) => {
                    return { ...d, order: (i + id * 7) % 4 };
                }).sort((a, b) => a.order - b.order);
            }

            // Get walls known to this bot
            getKnownWalls(r, c) {
                const key = `${r},${c}`;
                if (!this.knowledge[key]) {
                    return this.maze.getWalls(r, c);
                }
                return this.knowledge[key];
            }

            // Check if a cell is accessible from current position
            canMove(direction) {
                const walls = this.getKnownWalls(this.pos.r, this.pos.c);

                // If we know there's no wall in that direction, we can move
                if (!walls[direction]) return true;

                // Otherwise, check actual maze walls
                const actualWalls = this.maze.getWalls(this.pos.r, this.pos.c);
                return !actualWalls[direction];
            }

            // Update bot's knowledge of the maze
            updateKnowledge(r, c) {
                const key = `${r},${c}`;

                if (!this.knowledge[key]) {
                    // Record walls at this cell
                    this.knowledge[key] = this.maze.getWalls(r, c);

                    // Mark as explored
                    this.exploredCells.add(key);
                }
            }

            // Move the bot according to DFS/Tremaux rules
            move() {
                if (this.isFinished) return;

                const currentKey = `${this.pos.r},${this.pos.c}`;

                // Update knowledge of current cell
                this.updateKnowledge(this.pos.r, this.pos.c);

                // Check if we're at the exit
                if (this.pos.r === this.maze.exit.r && this.pos.c === this.maze.exit.c) {
                    this.finishTick = game.elapsed;
                    this.isFinished = true;
                    return;
                }

                // Get available directions from current cell
                const walls = this.getKnownWalls(this.pos.r, this.pos.c);

                // Find unexplored or backtracking options (DFS/Tremaux)
                let nextDir = null;

                for (const d of this.directionOrder) {
                    // Skip if there's a wall in this direction
                    if (walls[d.dir]) continue;

                    const nr = this.pos.r + d.dr;
                    const nc = this.pos.c + d.dc;
                    const neighborKey = `${nr},${nc}`;

                    // If we haven't visited this cell yet, go there
                    if (!this.exploredCells.has(neighborKey)) {
                        nextDir = d;
                        break;
                    }
                }

                // If no unexplored directions, try backtracking (to a cell with fewer than 3 walls)
                if (!nextDir) {
                    for (const d of this.directionOrder) {
                        if (walls[d.dir]) continue;

                        const nr = this.pos.r + d.dr;
                        const nc = this.pos.c + d.dc;
                        const neighborKey = `${nr},${nc}`;

                        // If we've visited this cell before and it's not a dead end, backtrack
                        if (this.exploredCells.has(neighborKey)) {
                            nextDir = d;
                            break;
                        }
                    }
                }

                // If still no direction, we're at a dead end - mark as dead end and try to backtrack
                if (!nextDir) {
                    // Mark current cell as dead end (if not already)
                    if (!this.deadEnds.some(d => d.r === this.pos.r && d.c === this.pos.c)) {
                        this.deadEnds.push({ r: this.pos.r, c: this.pos.c });
                    }

                    // Try to find any direction to backtrack
                    for (const d of this.directionOrder) {
                        if (walls[d.dir]) continue;

                        const nr = this.pos.r + d.dr;
                        const nc = this.pos.c + d.dc;
                        nextDir = d;
                        break;
                    }
                }

                // If we still can't move, stay put
                if (!nextDir) return;

                // Move to the next cell
                const nextR = this.pos.r + nextDir.dr;
                const nextC = this.pos.c + nextDir.dc;

                // Update position
                this.fromPos = { ...this.pos };
                this.toPos = { r: nextR, c: nextC };
                this.interpolationProgress = 0;
            }

            // Update interpolation and return true if moved to a new cell
            updateInterpolation() {
                if (!this.toPos) return false;

                this.interpolationProgress += 0.1; // Smooth movement speed

                if (this.interpolationProgress >= 1) {
                    this.pos = { ...this.toPos };
                    this.path.push({ r: this.pos.r, c: this.pos.c });
                    this.toPos = null;
                    return true;
                }

                return false;
            }

            // Get current position for rendering
            getCurrentPosition() {
                if (!this.toPos) return this.pos;

                const t = this.interpolationProgress;
                return {
                    r: this.fromPos.r + (this.toPos.r - this.fromPos.r) * t,
                    c: this.fromPos.c + (this.toPos.c - this.fromPos.c) * t
                };
            }
        }

        // Game controller
        class Game {
            constructor() {
                this.size = { rows: 15, cols: 15 };
                this.maze = null;
                this.bots = [];
                this.elapsed = 0;
                this.seed = Math.floor(Math.random() * 1000000);

                // DOM elements
                this.canvas = document.getElementById('maze');
                this.ctx = this.canvas.getContext('2d');
                this.completedEl = document.getElementById('completed');
                this.timerEl = document.getElementById('timer');
                this.resetBtn = document.getElementById('reset');

                // Bind reset button
                this.resetBtn.addEventListener('click', () => {
                    this.reset();
                });

                // Initialize game
                this.reset();
            }

            reset(seed) {
                if (seed !== undefined) {
                    this.seed = seed;
                } else {
                    this.seed = Math.floor(Math.random() * 1000000);
                }

                const rng = new SeededRandom(this.seed);

                // Generate maze
                this.maze = new Maze(this.size.rows, this.size.cols, rng);

                // Create bots with different exploration preferences
                this.bots = [];
                for (let i = 0; i < 24; i++) {
                    const botRng = new SeededRandom(this.seed + i * 1000);
                    this.bots.push(new Bot(i, this.maze, botRng));
                }

                // Reset timer
                this.elapsed = 0;

                // Update UI
                this.updateUI();
                this.drawMaze();
            }

            tick(n) {
                for (let i = 0; i < n; i++) {
                    let allFinished = true;

                    // Move each bot
                    for (const bot of this.bots) {
                        if (!bot.isFinished) {
                            allFinished = false;
                            bot.move();
                        }
                    }

                    // Update interpolation for smooth movement
                    for (const bot of this.bots) {
                        bot.updateInterpolation();
                    }

                    // Increment timer only if not all bots have finished
                    if (!allFinished) {
                        this.elapsed++;
                    }

                    // Check if we've reached the limit
                    if (this.elapsed >= 20000) break;
                }

                // Update UI
                this.updateUI();
                this.drawMaze();
            }

            updateUI() {
                const completed = this.bots.filter(bot => bot.isFinished).length;
                this.completedEl.textContent = `Completed: ${completed}/${this.bots.length}`;
                this.timerEl.textContent = `Time: ${this.elapsed} ticks`;
            }

            drawMaze() {
                // Clear canvas
                this.ctx.fillStyle = '#f5f5f5';
                this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

                const cellSize = Math.min(
                    this.canvas.width / (this.size.cols + 2),
                    this.canvas.height / (this.size.rows + 2)
                );

                const offsetX = (this.canvas.width - cellSize * this.size.cols) / 2;
                const offsetY = (this.canvas.height - cellSize * this.size.rows) / 2;

                // Draw maze walls
                for (let r = 0; r < this.size.rows; r++) {
                    for (let c = 0; c < this.size.cols; c++) {
                        const x = offsetX + c * cellSize;
                        const y = offsetY + r * cellSize;

                        // Draw cell background
                        if (r === this.maze.spawn.r && c === this.maze.spawn.c) {
                            this.ctx.fillStyle = '#e0f7fa'; // Spawn area
                        } else if (r === this.maze.exit.r && c === this.maze.exit.c) {
                            this.ctx.fillStyle = '#c8e6c9'; // Exit area
                        } else {
                            this.ctx.fillStyle = '#ffffff';
                        }

                        this.ctx.fillRect(x, y, cellSize, cellSize);

                        // Draw walls
                        const walls = this.maze.getWalls(r, c);
                        this.ctx.strokeStyle = '#333';
                        this.ctx.lineWidth = 2;

                        if (walls.n) {
                            this.ctx.beginPath();
                            this.ctx.moveTo(x, y);
                            this.ctx.lineTo(x + cellSize, y);
                            this.ctx.stroke();
                        }

                        if (walls.e) {
                            this.ctx.beginPath();
                            this.ctx.moveTo(x + cellSize, y);
                            this.ctx.lineTo(x + cellSize, y + cellSize);
                            this.ctx.stroke();
                        }

                        if (walls.s) {
                            this.ctx.beginPath();
                            this.ctx.moveTo(x + cellSize, y + cellSize);
                            this.ctx.lineTo(x, y + cellSize);
                            this.ctx.stroke();
                        }

                        if (walls.w) {
                            this.ctx.beginPath();
                            this.ctx.moveTo(x, y + cellSize);
                            this.ctx.lineTo(x, y);
                            this.ctx.stroke();
                        }
                    }
                }

                // Draw exit marker
                const exitX = offsetX + this.maze.exit.c * cellSize + cellSize / 2;
                const exitY = offsetY + this.maze.exit.r * cellSize + cellSize / 2;

                this.ctx.fillStyle = '#4CAF50';
                this.ctx.beginPath();
                this.ctx.arc(exitX, exitY, cellSize / 3, 0, Math.PI * 2);
                this.ctx.fill();

                // Draw bots
                for (const bot of this.bots) {
                    const pos = bot.getCurrentPosition();
                    const x = offsetX + pos.c * cellSize + cellSize / 2;
                    const y = offsetY + pos.r * cellSize + cellSize / 2;

                    // Color based on completion status
                    if (bot.isFinished) {
                        this.ctx.fillStyle = '#4CAF50'; // Green for finished bots
                    } else {
                        // Different colors for different bots
                        const hue = (bot.id * 137.5) % 360;
                        this.ctx.fillStyle = `hsl(${hue}, 80%, 50%)`;
                    }

                    this.ctx.beginPath();
                    this.ctx.arc(x, y, cellSize / 4, 0, Math.PI * 2);
                    this.ctx.fill();
                }
            }

            // API methods
            tick(n) {
                return this.tick(n);
            }

            reset(seed) {
                return this.reset(seed);
            }

            get elapsed() {
                return this.elapsed;
            }

            get size() {
                return { rows: this.size.rows, cols: this.size.cols };
            }

            get spawn() {
                return { ...this.maze.spawn };
            }

            get exit() {
                return { ...this.maze.exit };
            }

            walls(r, c) {
                return this.maze.getWalls(r, c);
            }

            get bots() {
                // Return a copy of bot data
                return this.bots.map(bot => ({
                    path: [...bot.path],
                    deadEnds: [...bot.deadEnds],
                    finishTick: bot.finishTick
                }));
            }
        }

        // Initialize game
        const game = new Game();

        // Expose to window for API access
        window.game = {
            tick: (n) => game.tick(n),
            reset: (seed) => game.reset(seed),
            get elapsed() { return game.elapsed; },
            get size() { return game.size; },
            get spawn() { return game.spawn; },
            get exit() { return game.exit; },
            walls: (r, c) => game.walls(r, c),
            get bots() { return game.bots; }
        };

        // Initial draw
        game.drawMaze();
    </script>
</body>
</html>
